export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期三。她從早上開始搜千田浩介。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "搜尋引擎的結果很少。第一頁全是新聞——「灣岸新交通第七車死亡事件」「車內男性死亡」「系統工程相關男性倒臥車廂」。沒有維基百科。沒有公司頁面。沒有社群帳號。沒有演講影片。沒有論文。只有新聞。而新聞裡的千田浩介只有一個身分——「系統工程相關男性」。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）系統工程相關。不是工程師。不是研究員。是「相關」。連職稱都不給他。", background: Background.Chapter_4_Ch4_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻了五頁。第五頁開始出現無關結果——另一個千田、另一個浩介、一篇二十年前的地產新聞裡剛好出現了這三個字的組合。她停了。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她換了搜尋方式。她用英文拼他的名字。Chida Kosuke。結果更少。一個舊的技術研討會議程頁面，名字出現在「與會者名單」裡，但連結已經失效。一個 PDF 的標題殘留在搜尋引擎的快取裡——標題被截斷了，只看得見前半段。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）「大規模災害警報同步介面⋯⋯」。後面被截了。", background: Background.Chapter_4_Ch4_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點進快取。頁面載入了一半。文字是破碎的——CSS 沒有載入，圖片是灰色的佔位框，但文字還在。那是一份幾年前的技術講座議程。主辦單位是某個公共安全技術協會。講座名稱：「大規模災害警報同步介面與使用者端設計」。講者名單裡有千田浩介。職稱寫的是「系統介面設計工程師」。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）災害警報同步介面。使用者端設計。他不是「系統工程相關男性」。他是做災害警報同步系統的。", background: Background.Chapter_4_Ch4_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把這個快取頁面的文字全部複製進備忘錄。然後她繼續搜。她找到那家公司的官網——千田的雇主。她翻到「團隊介紹」頁面。頁面載入了。她往下捲。沒有千田浩介。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她用站內搜尋。零結果。她用搜尋引擎查那家公司加上千田的名字。第一條結果是公司頁面的舊快取——一個已被刪除的員工介紹頁。快取標題還在。「千田浩介／資深系統工程師」。但點進去是 404。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）公司頁面刪了他的介紹。但舊快取的標題還留著。資深系統工程師。不是「相關男性」。", background: Background.Chapter_4_Ch4_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她靠在椅背上。天花板有一條裂縫，她盯著那條裂縫。她在想。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）千田。災害警報同步介面。灣岸新交通。那天晚上的防災同步測試。手機警報推送延遲了七秒。千田的遺言——「不要救東京」。", background: Background.Chapter_4_Ch4_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這些東西在她腦子裡排成一列。像便條紙貼在牆上。每一張之間都有一段空白。她不知道那些空白裡有什麼。但她知道它們指向同一個方向。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）可能不是巧合。", background: Background.Chapter_4_Ch4_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拿起手機。她打了一通電話。不是給客服。是給她兼職的那家網路調查媒體的前輩。", background: Background.Chapter_4_Ch4_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "前輩接了。她叫澪直接說。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "前輩，能不能幫我查一個人？千田浩介。就是灣岸新交通那個事故的死者。我找到他以前做過災害警報同步系統，但他公司的頁面把他的介紹刪了。我想看看舊快取和公開資料裡還有沒有別的線索。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "前輩沉默了幾秒。澪聽見鍵盤聲。前輩在邊聽邊查。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "澪。妳現在在這個案子裡是什麼角色？", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我是重大參考人。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "電話那頭又沉默了。這次的沉默更長。鍵盤聲停了。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "澪，這不是報導。這是妳自己的刑事風險。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我知道。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "妳不知道。妳現在是重大參考人，還去查死者背景、災害警報系統、交通公司——在妳看來這是找真相，但在警方眼裡，這就是涉案者在編故事。妳查的每一筆紀錄，都會變成妳「預謀蒐集資料影響輿論」的證據。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不是在編故事。我只是在查——", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "我知道妳沒有。但「我知道」沒有用。有用的是證據。妳手上有什麼？", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有說話。她手上有什麼。三個矛盾。但三個矛盾都在別人的證物袋裡。她有記憶。記憶不是證據。她有一面小鏡子。鏡子和案件無關。她有一個快取頁面。快取頁面只證明千田做過災害警報系統。那不是證據。那只是一個死者的履歷碎片。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "如果妳想發稿，我不會幫妳發。不是不信妳，是現在任何字都會被對方拿來當作妳在編故事的證據。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯我知道。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "找律師。先找律師。透過律師去申請事故車的原始資料。那是正路。唯一能保護妳又拿到東西的正路。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "來得及嗎？他們說資料已經轉入安全流程了。下週一之前可能就被轉走了。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "前輩又沉默了。這次的沉默裡沒有鍵盤聲。只有很遠的車聲。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "正式程序不可能在資料轉送前拿到原始影像。這點妳知道。我也知道。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯那怎麼辦。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.MediaSenior, character: "調查媒體前輩", dialogue: "先活過這一週。先不要把自己推進更壞的位置。律師我幫妳問。但澪——不要自己再去查了。不要再去那個車輛基地。不要再用公開入口查任何東西。妳現在留下的每一個紀錄，都是在替別人製造問題。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "電話掛了。澪坐在椅子上。螢幕還亮著。備忘錄裡是她今天打進去的東西——7-CAM、T-? / CAM、封存條、公共安全資料保全流程、技術班。還有今天的——大規模災害警報同步介面、使用者端設計、舊快取標題、404。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）千田做過災害警報同步系統。灣岸新交通那天晚上在做防災同步測試。我的手機警報比看板晚了七秒。千田的遺言是「不要救東京」。悠真在睡眠研究中心。這些可能不是巧合。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著備忘錄。她沒有把它們連成一條線。她連不起來。中間的空白太多了。她只有碎片。碎片不是圖。碎片只是碎片。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）但我至少知道千田不是路人。他知道些什麼。他帶著那些東西上了第七車。他把外殼塞給我。然後他死了。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把螢幕按滅。房間暗下來。窗外是星期三的傍晚。她沒有開燈。她坐在暗裡，想著千田——一個她只見過幾分鐘的人，一個在車上倒下之前對她說了兩句話的人。不要救東京。他們會改監視器。別相信畫面。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說得對。他們改了。畫面少了一段。而她正在被那個少了一段的畫面定義。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）他知道的比我以為的多。他上車之前就已經在流血了。他知道自己會死。他還是來了。", background: Background.Chapter_4_Ch4_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她閉上眼睛。她沒有再查了。前輩說得對——她現在留下的每一個紀錄，都會變成別人的問題。但她已經留下了。客服電話。基地外的腳步。快取頁面。這些都在某個地方存著。她刪不掉。", background: Background.Chapter_4_Ch4_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她只能等。等律師。等正式程序。等一個她知道來不及的東西。", background: Background.Chapter_4_Ch4_Act5_S1 },
];
